// Client ignores default values if member values are present in the response.
TEST(RestJsonResponseTest, RestJsonClientIgnoresDefaultValuesIfMemberValuesArePresentInResponse) {
  Fixture fixture = MakeFixture();
  fixture.transport->next_response.status = 200;
  fixture.transport->next_response.headers.Set("Content-Type", "application/json");
  fixture.transport->next_response.body = "{\n    \"defaultString\": \"bye\",\n    \"defaultBoolean\": false,\n    \"defaultList\": [\"a\"],\n    \"defaultDocumentMap\": {\"name\": \"Jack\"},\n    \"defaultDocumentString\": \"bye\",\n    \"defaultDocumentBoolean\": false,\n    \"defaultDocumentList\": [\"b\"],\n    \"defaultNullDocument\": \"notNull\",\n    \"defaultTimestamp\": 2,\n    \"defaultBlob\": \"aGk=\",\n    \"defaultByte\": 2,\n    \"defaultShort\": 2,\n    \"defaultInteger\": 20,\n    \"defaultLong\": 200,\n    \"defaultFloat\": 2.0,\n    \"defaultDouble\": 2.0,\n    \"defaultMap\": {\"name\": \"Jack\"},\n    \"defaultEnum\": \"BAR\",\n    \"defaultIntEnum\": 2,\n    \"emptyString\": \"foo\",\n    \"falseBoolean\": true,\n    \"emptyBlob\": \"aGk=\",\n    \"zeroByte\": 1,\n    \"zeroShort\": 1,\n    \"zeroInteger\": 1,\n    \"zeroLong\": 1,\n    \"zeroFloat\": 1.0,\n    \"zeroDouble\": 1.0\n}";
  const auto outcome = fixture.client.OperationWithDefaults(OperationWithDefaultsInput{});
  ASSERT_TRUE(outcome.ok()) << outcome.error().message();
  const OperationWithDefaultsOutput expected = [] {
  OperationWithDefaultsOutput v{};
  v.defaultString = "bye";
  v.defaultBoolean = false;
  v.defaultList = std::vector<std::string>{"a"};
  v.defaultDocumentMap = [] {
  smithy::DocumentMap map;
  map.emplace("name", smithy::Document(std::string("Jack")));
  return smithy::Document(std::move(map));
}();
  v.defaultDocumentString = smithy::Document(std::string("bye"));
  v.defaultDocumentBoolean = smithy::Document(false);
  v.defaultDocumentList = [] {
  smithy::DocumentList list;
  list.emplace_back(smithy::Document(std::string("b")));
  return smithy::Document(std::move(list));
}();
  v.defaultNullDocument = smithy::Document(std::string("notNull"));
  v.defaultTimestamp = smithy::Timestamp::FromEpochMilliseconds(2000LL);
  v.defaultBlob = smithy::Blob::FromString("hi");
  v.defaultByte = 2;
  v.defaultShort = 2;
  v.defaultInteger = 20;
  v.defaultLong = 200LL;
  v.defaultFloat = 2.0F;
  v.defaultDouble = 2.0;
  v.defaultMap = std::map<std::string, std::string>{{"name", "Jack"}};
  v.defaultEnum = TestEnum::FromString("BAR");
  v.defaultIntEnum = static_cast<TestIntEnum>(2);
  v.emptyString = "foo";
  v.falseBoolean = true;
  v.emptyBlob = smithy::Blob::FromString("hi");
  v.zeroByte = 1;
  v.zeroShort = 1;
  v.zeroInteger = 1;
  v.zeroLong = 1LL;
  v.zeroFloat = 1.0F;
  v.zeroDouble = 1.0;
  return v;
}();
  EXPECT_EQ(*outcome, expected);
}

